#!/usr/bin/env bash
# =============================================================================
# CouchDB Seed Script (Document Database)
#
# Showcases: denormalized nested documents, flexible schemas, embedded arrays,
# mixed document types in the same database, and MapReduce views.
#
# Each book is a self-contained document with authors and reviews embedded
# directly — no joins required. Compare this to the normalized Postgres schema
# where the same data spans 6+ tables.
#
# Data: 120 books, 25 customers. Generated from data/books.json + data/customers.json.
# =============================================================================
set -euo pipefail

COUCH_HOST="${COUCH_HOST:-localhost}"
COUCH="http://launchpad:dontdothis@${COUCH_HOST}:5984"

echo "==> Waiting for CouchDB to be ready..."
until curl -sf "${COUCH}/" > /dev/null 2>&1; do
  sleep 1
done
echo "==> CouchDB is up."

# Create the bookstore database (idempotent — CouchDB returns 412 if it exists).
echo "==> Creating 'bookstore' database..."
curl -sf -X PUT "${COUCH}/bookstore" > /dev/null 2>&1 || true

# ---------------------------------------------------------------------------
# Helper: insert a document, skip if already exists (by _id).
# ---------------------------------------------------------------------------
put_doc() {
  local id="$1"
  local json="$2"
  # Check if doc already exists
  if curl -sf "${COUCH}/bookstore/${id}" > /dev/null 2>&1; then
    echo "    (skip) ${id} already exists"
    return
  fi
  curl -sf -X PUT "${COUCH}/bookstore/${id}" \
    -H "Content-Type: application/json" \
    -d "${json}" > /dev/null
  echo "    + ${id}"
}

# ---------------------------------------------------------------------------
# Book documents — notice how authors, reviews, and metadata are all embedded.
# In a relational DB this would require JOINs across books, authors,
# book_authors, reviews, and customers. Here it's a single document read.
# ---------------------------------------------------------------------------
echo "==> Inserting book documents..."

put_doc "book:dune" '{"type": "book", "title": "Dune", "isbn": "978-0441013593", "genre": "Science Fiction", "price": 9.99, "published_date": "1965-08-01", "in_stock": true, "authors": [{"name": "Frank Herbert", "born_year": 1920}], "reviews": [{"customer": "Alice Johnson", "rating": 5, "body": "A masterpiece of science fiction. The world-building is unmatched."}, {"customer": "Bob Smith", "rating": 4, "body": "Dense but rewarding. The political intrigue kept me hooked."}, {"customer": "Elena Rodriguez", "rating": 5, "body": "Changed the way I think about ecology and politics in fiction."}, {"customer": "Keiko Tanaka", "rating": 4, "body": "Epic in scope. Herbert built something truly unique."}, {"customer": "Priya Sharma", "rating": 3, "body": "Ambitious but overwritten. The pacing drags in the middle third."}, {"customer": "Viktor Petrov", "rating": 2, "body": "Too many made-up words and political monologues. I couldn'\''t finish it."}], "tags": ["desert", "politics", "ecology", "epic", "spice"]}'

