# ---------------------------------------------------------------------------
# Design document with MapReduce views — CouchDB's query mechanism.
# ---------------------------------------------------------------------------
echo "==> Creating design document (views)..."

put_doc "_design/bookstore" '{
  "views": {
    "books_by_genre": {
      "map": "function(doc) { if (doc.type === '\''book'\'') emit(doc.genre, {title: doc.title, price: doc.price}); }"
    },
    "avg_rating": {
      "map": "function(doc) { if (doc.type === '\''book'\'' && doc.reviews) { doc.reviews.forEach(function(r) { emit(doc._id, r.rating); }); } }",
      "reduce": "_stats"
    }
  }
}'

echo "==> CouchDB seeding complete."
echo ""
